#include <bits/stdc++.h>using namespace std;typedef long long ll; int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int t;    cin >> t;    while(t--) {        ll n, k;        cin >> n >> k;        vector<ll> a(n);        for(int i = 0; i < n; i++) {            cin >> a[i];        }        for(int i=0;i<63;i++){            for(int j=0;j<n;j++){                if(!(a[j]&(1LL<<i))){                    if(k-(1LL<<i)>=0){                        a[j]|=(1LL<<i);                        k-=(1LL<<i);                    }                    else{                        break;                    }                }            }        }        ll ans=0;        for(int i=0;i<n;i++){            ans+=__builtin_popcountll(a[i]);        }        cout << ans << endl;    }    return 0;}